    /**
     * @ignore
     * @method
     * @name hyperliquid#parsePredictionOrder
     * @description parses a raw hyperliquid order object into a unified order object
     * @param {object} order the raw order object
     * @param {object} [market] the market the order belongs to
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public Object parsePredictionOrder(Object order, Object... optionalArgs)
    {
        //
        // from frontendOpenOrders:
        // {
        //   "coin": "#10",
        //   "limitPx": "0.44",
        //   "oid": 12345,
        //   "origSz": "100",
        //   "side": "B",
        //   "sz": "100",
        //   "timestamp": 1704346468838
        // }
        //
        // from historicalOrders / orderStatus:
        // {
        //   "order": { "coin": "#10", "limitPx": "0.44", "oid": "12345", "origSz": "100", "side": "B", "sz": "100", "tif": "Gtc", "timestamp": "1704346468838" },
        //   "status": "open",
        //   "statusTimestamp": 1704346468838
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object entry = this.safeDict(order, "order", order); // eslint-disable-line
        Object status = this.parseOrderStatus(this.safeString2(order, "ccxtStatus", "status"));
        Object coin = this.safeString(entry, "coin");
        Object outcomeObj = this.safeOutcome(coin, ((Object)market));
        Object marketSymbol = this.safeString(outcomeObj, "outcome");
        Object resolvedMarket = ((Helpers.isTrue(marketSymbol))) ? this.safeMarket(marketSymbol, ((Object)market)) : market;
        Object sideRaw = this.safeString(entry, "side");
        Object side = ((Helpers.isTrue((Helpers.isEqual(sideRaw, "B"))))) ? "buy" : "sell";
        Object totalAmount = this.safeString(entry, "origSz");
        Object remaining = this.safeString(entry, "sz");
        Object filled = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(remaining, null))) && Helpers.isTrue((!Helpers.isEqual(totalAmount, null)))))
        {
            filled = Precise.stringSub(totalAmount, remaining);
        }
        Object timestamp = this.safeInteger(entry, "timestamp");
        Object tifRaw = this.safeString(entry, "tif");
        Object tif = this.parseTimeInForce(tifRaw);
        Object postOnly = (Helpers.isEqual(tif, "PO"));
        final Object finalTif = tif;
        final Object finalTotalAmount = totalAmount;
        final Object finalFilled = filled;
        final Object finalRemaining = remaining;
        return this.safePredictionOrder(new java.util.HashMap<String, Object>() {{
            put( "id", HyperliquidCore.this.safeString(entry, "oid") );
            put( "clientOrderId", HyperliquidCore.this.safeString(entry, "cloid") );
            put( "info", order );
            put( "timestamp", timestamp );
            put( "datetime", HyperliquidCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", status );
            put( "outcome", HyperliquidCore.this.safeString(outcomeObj, "outcome") );
            put( "outcomeId", HyperliquidCore.this.safeString(outcomeObj, "id") );
            put( "label", HyperliquidCore.this.safeString(outcomeObj, "label") );
            put( "market", HyperliquidCore.this.safeString(outcomeObj, "market") );
            put( "type", HyperliquidCore.this.parseOrderType(HyperliquidCore.this.safeString(entry, "orderType", "limit")) );
            put( "timeInForce", finalTif );
            put( "postOnly", postOnly );
            put( "reduceOnly", HyperliquidCore.this.safeBool(entry, "reduceOnly", false) );
            put( "side", side );
            put( "price", HyperliquidCore.this.safeNumber(entry, "limitPx") );
            put( "triggerPrice", ((Helpers.isTrue(HyperliquidCore.this.safeBool(entry, "isTrigger")))) ? HyperliquidCore.this.safeNumber(entry, "triggerPx") : null );
            put( "amount", HyperliquidCore.this.parseNumber(finalTotalAmount) );
            put( "cost", null );
            put( "average", HyperliquidCore.this.safeNumber(entry, "avgPx") );
            put( "filled", HyperliquidCore.this.parseNumber(finalFilled) );
            put( "remaining", HyperliquidCore.this.parseNumber(finalRemaining) );
            put( "fee", null );
            put( "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()) );
        }}, resolvedMarket);
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "triggered", "open" );
            put( "filled", "closed" );
            put( "open", "open" );
            put( "canceled", "canceled" );
            put( "rejected", "rejected" );
            put( "marginCanceled", "canceled" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        if (Helpers.isTrue(((String)status).endsWith(((String)"Rejected"))))
        {
            return "rejected";
        }
        if (Helpers.isTrue(((String)status).endsWith(((String)"Canceled"))))
        {
            return "canceled";
        }
        return this.safeString(statuses, status, status);
    }

    public Object parseOrderType(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "stop limit", "limit" );
            put( "stop market", "market" );
        }};
        Object statusLower = ((Helpers.isTrue(status))) ? ((String)status).toLowerCase() : null;
        return this.safeString(statuses, statusLower, statusLower);
    }

    public Object parseTimeInForce(Object timeInForce)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "gtc", "GTC" );
            put( "ioc", "IOC" );
            put( "fok", "FOK" );
            put( "alo", "PO" );
        }};
        Object tifLower = ((Helpers.isTrue(timeInForce))) ? ((String)timeInForce).toLowerCase() : null;
        return this.safeString(statuses, tifLower, timeInForce);
    }

